3_real_world_example.code:
function Email(address) {
  this.address = address;
}

const myEmail = new Email('test@test.com');
const fakeEmail = { address: 'fake@test.com' }; // Just a plain object

console.log(myEmail instanceof Email); // true
console.log(fakeEmail instanceof Email); // false

function sendEmail(emailObj) {
  if (!(emailObj instanceof Email)) {
    throw new Error('Must provide a valid Email instance!');
  }
  console.log('Sending to ' + emailObj.address);
}

